    studies: [{"title": "Effects of an ACE inhibitor, ramipril, on cardiovascular events in high-risk patients (HOPE)", "authors": "Yusuf et al.", "year": 2000, "journal": "NEJM", "design": "RCT", "n": 9297, "url": "https://www.nejm.org/doi/10.1056/NEJM200001203420301", "finding": "22% reduction in MI, stroke, or CV death over 5 years. 16% reduction in all-cause mortality.", "limitations": "High-risk cohort."}, {"title": "A Randomized Trial of Intensive vs Standard BP Control (SPRINT)", "authors": "SPRINT Research Group", "year": 2015, "journal": "NEJM", "design": "RCT", "n": 9361, "url": "https://www.nejm.org/doi/10.1056/NEJMoa1511939", "finding": "Intensive control (SBP <120) reduced all-cause mortality 27% and CV events 25% vs standard (<140).", "limitations": "Stopped early; high-CV-risk cohort; oscillometric BP measurement nuance."}],
