    studies: [{"title": "Primary Prevention of Cardiovascular Disease with a Mediterranean Diet (PREDIMED)", "authors": "Estruch et al.", "year": 0.9975222993062438, "journal": "NEJM", "design": "RCT", "n": 7447, "url": "https://www.nejm.org/doi/10.1056/NEJMoa1800389", "finding": "Mediterranean diet + EVOO (or + nuts) reduced major CV events ~30% vs low-fat control.", "limitations": "Re-analyzed after randomization concern; effect held."}, {"title": "Olive Oil Consumption and Cardiovascular Disease (Guasch-Ferré et al.)", "authors": "Guasch-Ferré et al.", "year": 2020, "journal": "JACC", "design": "Cohort", "n": 92383, "url": "https://www.jacc.org/doi/10.1016/j.jacc.2020.02.036", "finding": "Highest olive oil intake (>0.5 tbsp/day) associated with 14% lower CHD risk vs lowest. Replacing butter/margarine with olive oil reduced CHD risk.", "limitations": "Observational; food-based."}, {"title": "Olive oil consumption and total and cause-specific mortality (Guasch-Ferré et al.)", "authors": "Guasch-Ferré et al.", "year": 2022, "journal": "Journal of the American College of Cardiology", "design": "Cohort", "n": 92383, "url": "https://www.jacc.org/doi/10.1016/j.jacc.2021.10.041", "finding": "Highest olive oil intake associated with 19% lower all-cause mortality, 19% lower CV mortality, 17% lower cancer mortality, 29% lower neurodegenerative mortality, 18% lower respiratory mortality.", "limitations": "Observational; food-based."}],
