    studies: [{"title": "A systematic review, meta-analysis and meta-regression of the effect of protein supplementation on resistance training-induced gains in muscle mass and strength in healthy adults (Morton 2018)", "authors": "Morton et al.", "year": 2018, "journal": "British Journal of Sports Medicine", "design": "Meta-analysis of 49 RCTs", "n": 1863, "url": "https://pubmed.ncbi.nlm.nih.gov/28698222/", "finding": "Protein supplementation during resistance training increased fat-free mass by 0.3 kg and 1RM strength by 9% beyond training alone. Dose-dependent up to ~1.6g/kg/day total intake.", "limitations": "Heterogeneous protein sources; mostly young/middle-aged adults; effect plateau at ~1.6g/kg."}, {"title": "Evidence-based recommendations for optimal dietary protein intake in older people (PROT-AGE Study Group, Bauer 2013)", "authors": "Bauer et al.", "year": 2013, "journal": "Journal of the American Medical Directors Association", "design": "Consensus statement / systematic review", "n": 0, "url": "https://pubmed.ncbi.nlm.nih.gov/23867520/", "finding": "Older adults benefit from 1.0-1.2g/kg/day (healthy) or 1.2-1.5g/kg/day (sick/recovering), with 25-30g protein per meal. Whey/leucine-rich sources particularly effective for hitting MPS threshold.", "limitations": "Consensus statement; pre-recent trials; recommendations conservative."}, {"title": "Whey protein hydrolysate produces a greater muscle protein synthetic response after resistance exercise than soy or casein (Devries 2018)", "authors": "Devries et al.", "year": 2018, "journal": "Journal of Nutrition", "design": "Randomized crossover", "n": 24, "url": "https://pubmed.ncbi.nlm.nih.gov/?term=Whey%20protein%20hydrolysate%20produces%20a%20greater%20muscle%20protein%20synthetic%20response%20after%20resistance%20exercise%20than%20soy%20or%20casein%20%28Devries%202018%29", "finding": "30g whey hydrolysate produced ~30% greater post-exercise MPS than equivalent soy or casein in older adults. Differences less pronounced at higher doses.", "limitations": "Small (n=24); acute MPS measurement; whey hydrolysate (premium form)."}, {"title": "Resistance exercise enhances myofibrillar protein synthesis with graded intakes of whey protein in older men (Yang 2012)", "authors": "Yang et al.", "year": 2012, "journal": "British Journal of Sports Medicine", "design": "Dose-response trial", "n": 37, "url": "https://pubmed.ncbi.nlm.nih.gov/?term=Resistance%20exercise%20enhances%20myofibrillar%20protein%20synthesis%20with%20graded%20intakes%20of%20whey%20protein%20in%20older%20men%20%28Yang%202012%29", "finding": "Older men required 40g whey to maximise MPS, while 20g sufficient in younger adults. Direct evidence of anabolic resistance with age.", "limitations": "Acute MPS measurement; small dose-response cohort; men only."}],
