    studies: [{"title": "Coffee consumption and health: umbrella review of meta-analyses of multiple health outcomes", "authors": "Poole R, Kennedy OJ, Roderick P, Fallowfield JA, Hayes PC, Parkes J", "year": 2017, "journal": "BMJ", "design": "Umbrella review (201 meta-analyses)", "n": null, "url": "https://pubmed.ncbi.nlm.nih.gov/29167102/", "finding": "3-4 cups/day: 17% lower all-cause mortality, 19% lower CV mortality, 30% lower T2D incidence, 31% lower Parkinson's incidence, lower liver cirrhosis and HCC. J-shaped curve with optimal at 3-4 cups.", "limitations": "All observational. Healthy-user bias possible. Different coffee preparations bundled together."}, {"title": "Long-term coffee consumption, caffeine metabolism genetics, and risk of cardiovascular disease: a prospective analysis of up to 347,077 individuals", "authors": "Zhou A, Hyppönen E", "year": 2019, "journal": "Am J Clin Nutr", "design": "Prospective cohort (UK Biobank + Mendelian randomization)", "n": 347077, "url": "https://pubmed.ncbi.nlm.nih.gov/?term=Long-term%20coffee%20consumption%2C%20caffeine%20metabolism%20genetics%2C%20and%20risk%20of%20cardiovascular%20disease%3A%20a%20prospective%20analysis%20of%20up%20to%20347%2C077%20individuals", "finding": "Coffee consumption inversely associated with CVD risk in U-shape. Mendelian randomization using CYP1A2 and AHR variants supported a likely causal relationship for moderate intake (3-4 cups/day).", "limitations": "Mendelian randomization assumptions. UK-only cohort."}],
