    contras: ["History of calcium oxalate kidney stones (beets and spinach are high-oxalate)", "Active oral antiseptic use (kills nitrate-reducing bacteria)"],
    sides: ["Beeturia (red urine — harmless)", "Pink stool", "Mild GI upset from beetroot juice"],
    studies: [{"title": "Inorganic nitrate and beetroot juice supplementation reduces blood pressure in adults: a systematic review and meta-analysis", "authors": "Siervo M, Lara J, Ogbonmwan I, Mathers JC", "year": 2013, "journal": "J Nutr", "design": "Meta-analysis (16 RCTs)", "n": 254, "url": "https://pubmed.ncbi.nlm.nih.gov/23596162/", "finding": "Inorganic nitrate and beetroot juice reduced systolic BP by 4.4 mmHg and diastolic BP by 1.1 mmHg vs placebo. Effect dose-dependent (≥0.1 mmol nitrate/kg). Acute effect peaks 2-3h post-dose.", "limitations": "Short-term studies. Heterogeneous nitrate sources. Most trials in young healthy subjects."}, {"title": "Dietary nitrate provides sustained blood pressure lowering in hypertensive patients", "authors": "Kapil V, Khambata RS, Robertson A, Caulfield MJ, Ahluwalia A", "year": 2015, "journal": "Hypertension", "design": "RCT (4-week)", "n": 68, "url": "https://pubmed.ncbi.nlm.nih.gov/25421976/", "finding": "Beetroot juice (250 mL/day, ~6.4 mmol nitrate) reduced 24h ambulatory BP by ~7.7/2.4 mmHg in hypertensive patients over 4 weeks. Endothelial function improved. Tolerance did not develop.", "limitations": "Single-site UK trial. Modest sample. No hard endpoints."}],
